(6, 'Sheath Blight', 'Fungal disease caused by Rhizoctonia solani affecting leaf sheaths and can spread to leaves', 1, 0),
(7, 'Leaf Blast', 'Fungal disease caused by Pyricularia oryzae, one of the most destructive rice diseases', 1, 0),
(8, 'Leaf Scald', 'Bacterial disease causing lesions and yellowing, often related to nutrient imbalance', 1, 0),
(9, 'Narrow Brown Spot', 'Fungal disease causing narrow brown lesions on leaf blades', 1, 0),
(10, 'Neck Blast', 'Pyricularia oryzae infection of the panicle neck, causing panicle death and grain loss', 1, 0),
