(2, 'RC222', 'Tubigan 18 (Super Triple 2)', 114, 1, 6.10, 'MR', 'MR', 'MR', 'irrigated', 'IRRI / PhilRice', 'Moderately tolerant', 'Basal: 3 bags 14-14-14/ha; 21 DAT: 2 bags urea (46-0-0)/ha; 45 DAT: 1 bag urea + 1 bag MOP/ha', 'Moderately tolerant', 90, 'Good milling quality, medium amylose', 'Long slender', 'Moderate', 'Top preferred inbred variety of Filipino farmers nationwide. Best for irrigated lowlands. Consistently performs well both wet and dry season.', 101, '20×20 cm', 'Wet season (Jun–Oct) and Dry season (Nov–Apr) — All season', 10.00, 2009, 'certified', 'PhilRice Seed Unit / RCEF Program', 'Clay loam, Sandy loam', 'Tolerant to moderate heat', 'High', 'inbred', 'Intermittent irrigation, AWD (Alternate Wetting & Drying)', 'U', 'U', 'U', 'MR', 'MR', 'MR', 'MR', 'U', 'U'),
(3, 'RC160', 'Tubigan 14', 107, 1, 6.20, 'MR', 'MR', 'MR', 'irrigated', 'PhilRice', 'Moderately tolerant', 'Basal: 2 bags 46-0-0 + 3 bags 16-20-0/ha; 2nd application: 2 bags urea + 2 bags 14-14-14/ha', 'Moderately tolerant', 90, 'Premium — high milling and headrice recovery, low amylose, tender and aromatic', 'Long slender, heavy grains', 'Moderate', 'Yields better wet season than dry. Premium price from traders and millers due to high milling recovery. One of top 4 most popular varieties nationally. ⚠️ Do NOT plant in tungro-stricken areas.', 92, '25×25 cm', 'Wet season preferred (Jun–Oct), Dry season (Nov–Mar)', 8.20, 2006, '', 'PhilRice Seed Unit', 'Clay loam, All soil types', 'Tolerant', 'High', 'inbred', 'Intermittent irrigation', 'U', 'U', 'U', 'MR', 'R', 'MR', 'S', 'U', 'U'),
(4, 'RC216', 'Tubigan 17', 112, 1, 6.00, 'S', 'MR', 'MR', 'irrigated', 'PhilRice (cross: PJ7 × Matatag 1)', 'Moderately tolerant', 'Basal: 3 bags 14-14-14/ha; 21 DAT: 2 bags urea/ha; 45 DAT: 1 bag urea/ha', 'Moderately tolerant', 88, 'Good milling and headrice recovery, good eating quality', 'Long slender', 'Good', 'Versatile \"jack-of-all-trades\" variety. One of top 4 most popular nationally. Good taste preferred by consumers. ⚠️ Do NOT plant in areas with history of Blast or Tungro.', 96, '20×20 cm', 'All season — Wet (Jun–Oct) and Dry (Nov–Apr)', 9.70, 2009, 'certified', 'PhilRice Seed Unit', 'Clay loam, Sandy loam, All soil types', 'Tolerant', 'High', 'inbred', 'Intermittent irrigation, AWD', 'U', 'U', 'U', 'S', 'MR', 'MR', 'S', 'U', 'U'),
